import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';

const EventerRegister = () => {
  const navigate = useNavigate();

  const [eventerData, setEventerData] = useState({
    eventer_name: '',
    // Add other fields as necessary
  });

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setEventerData({ ...eventerData, [name]: value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const response = await fetch('http://localhost:8000/eventer/register', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(eventerData),
      });
      if (!response.ok) throw new Error('Eventer registration failed');
      // Reset form or handle success
      setEventerData({ eventer_name: '' });
      navigate('/home'); // Adjust the navigate path as needed
    } catch (error) {
      console.error(error);
    }
  };

  return (
    <form onSubmit={handleSubmit}>
      <label>
        Eventer Name:
        <input
          type="text"
          name="eventer_name"
          value={eventerData.eventer_name}
          onChange={handleInputChange}
          required
        />
      </label>
      {/* Add other input fields as necessary */}
      <button type="submit">Register Eventer</button>
    </form>
  );
};

export default EventerRegister;
